css:
.main-heading { 
    text-align: center;
    font-size: 24px;
    font-weight: bold;
    color: #2E5A88;
    text-transform: uppercase;
    letter-spacing: 1px;
    width: 100%;
    background-color: #000 !important; 
    color: #fff !important; 
    margin: 0; /* Remove any margin */
    padding: 8px 0; /* Adjust padding as needed */
}

.company-section { 
    display: flex; 
    justify-content: space-between; 
    align-items: center; 
    margin-top: 0; /* Remove top margin */
    padding-top: 10px; /* Add minimal padding if needed */
}

.logo-div img { 
    max-width: 100px; 
}

.info-div { 
    text-align: left; 
    font-size: 14px; 
}

.company-name { 
    font-size: 18px; 
    font-weight: bold; 
    text-transform: uppercase;
}

.orange-divider { 
    height: 4px; 
    background-color: #f28c38 !important; 
    margin: 10px 0 20px; 
}

.meta-row { 
    display: flex; 
    justify-content: space-between; 
    margin-bottom: 8px; 
    font-size: 14px; 
}

.meta-field { 
    display: flex; 
    align-items: center; 
    gap: 8px; 
}

.meta-label { 
    font-weight: bold; 
}

.custom-table { 
    width: 100%; 
    border-collapse: collapse; 
    font-size: 13px; 
    margin-bottom: 20px; 
}

.custom-table th, .custom-table td { 
    border: 1px solid #000; 
    padding: 6px 8px; 
    text-align: left; 
}

.custom-table th { 
    background-color: #000 !important; 
    color: #fff !important; 
}

.items-table th { 
    background-color: #333 !important; 
    color: white !important; 
}

.text-center { text-align: center; }
.text-right { text-align: right; }

@media print {
    .main-heading {
        background-color: #2E5A88 !important;
        color: white !important;
        -webkit-print-color-adjust: exact !important;
        print-color-adjust: exact !important;
        color-adjust: exact !important;
        margin: 0;
        padding: 8px 0;
    }

    .company-section {
        margin-top: 0;
        padding-top: 10px;
    }

    .custom-table tr.total-row {
        background-color: #f5f5f5 !important;
        -webkit-print-color-adjust: exact !important;
        print-color-adjust: exact !important;
    }

    td, th, tr, div[style*="background"] {
        -webkit-print-color-adjust: exact !important;
        print-color-adjust: exact !important;
    }
}
